package gui; import dao.ProjectDAO; import model.Project; import javax.swing.*; import java.awt.*; import java.util.List; public class ProjectTableForm extends JFrame { private ProjectDAO dao = new ProjectDAO(); public ProjectTableForm(String role, int userId) { setTitle(role.equals("ADMIN") ? "Projects" : "My Projects"); setExtendedState(JFrame.MAXIMIZED_BOTH); setLayout(new BorderLayout()); JPanel top = createHeader( role.equals("ADMIN") ? "PROJECTS" : "MY PROJECTS" ); JPanel container = new JPanel(); container.setLayout(new BoxLayout(container, BoxLayout.Y_AXIS)); container.setBackground(Color.WHITE); List<Project> projects; if (role.equals("ADMIN")) { projects = dao.getAll(); } else if (role.equals("EMPLOYEE")) { projects = dao.getByEmployee(userId); } else if (role.equals("CLIENT")) { projects = dao.getByClient(userId); } else { projects = java.util.Collections.emptyList(); }
if (projects.isEmpty()) { JLabel empty = new JLabel("No projects found", SwingConstants.CENTER); empty.setFont(new Font("Segoe UI", Font.BOLD, 20)); empty.setForeground(Color.GRAY); container.add(empty); } for (Project p : projects) { container.add(createCard( "ID: " + p.getId(), "Title: " + p.getTitle(), "Client ID: " + p.getClientId() )); } JScrollPane scroll = new JScrollPane(container); scroll.setBorder(null); JButton back = createBack(role, userId); add(top, BorderLayout.NORTH); add(scroll, BorderLayout.CENTER); add(back, BorderLayout.SOUTH); setVisible(true); } private JPanel createHeader(String title) { JPanel p = new JPanel(new BorderLayout()); p.setBackground(new Color(25, 25, 50)); JLabel lbl = new JLabel(title, SwingConstants.CENTER); lbl.setForeground(Color.WHITE); lbl.setFont(new Font("Segoe UI", Font.BOLD, 36)); p.add(lbl, BorderLayout.CENTER); return p; } private JPanel createCard(String... lines) { JPanel card = new JPanel(); card.setLayout(new GridLayout(lines.length, 1, 5, 5)); card.setBackground(Color.WHITE); card.setMaximumSize(new Dimension(Integer.MAX_VALUE, 120)); card.setBorder(BorderFactory.createCompoundBorder( BorderFactory.createLineBorder(new Color(200, 200, 200), 1), BorderFactory.createEmptyBorder(15, 15, 15, 15) )); for (String line : lines) { JLabel lbl = new JLabel(line); lbl.setFont(new Font("Segoe UI", Font.PLAIN, 18)); card.add(lbl); } return card; } private JButton createBack(String role, int userId) { JButton b = new JButton("Back"); b.setFont(new Font("Segoe UI", Font.BOLD, 16)); b.addActionListener(e -> { dispose(); new MainForm(role, "User", userId); }); return b; } }
